head.script:
//물류/공통(통합)/매출요율/하역/장비료관리

//-------------------------------------------------------------------------
// scwin.name : 
// scwin.desc : 전역변수 선언
//------------------------------------------------------------------------- 
scwin.pos_groupCode = 0;
scwin.searchFlag = true;
scwin.MSG_LO_CRM_001 = "변경 사항이 존재합니다. 진행하시겠습니까?"
scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");    // 서버를 기준으로 현재 날짜 반환
scwin.hid_portDistrictCd = "";
scwin.hid_portDistrictNm = "";
scwin.hid_adptDt = "";

scwin.onpageload = function () {
    let codeOptions = [
        {
            method: "getLuxeComboData",
            param1: "EquipmentEBC",
            param2: "retrieveLogisticsEquipmentClss",
            param3: ["ZZ210", "ZZ202", "ZZ201", "LH"],
            compID: "gr_basetrfList:eqKndCd"
        }
    ];

    $c.data.setGauceUtil(codeOptions);

    codeOptions = [
        //{ grpCd: 'ZZ208', compID: 'gr_basetrfList:eqNrmCd' },
        //{ grpCd: 'ZZ208', compID: 'acb_eqNrmCd_hid' },
        { grpCd: 'ZZ006', compID: 'gr_basetrfList:crcCd' }
    ];

    $c.data.setCommonCode(codeOptions, scwin.fn_setCommboGridEqKndCdAll);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_OnLoad
// scwin.desc : 화면로딩시 
//-------------------------------------------------------------------------   
scwin.f_OnLoad = function () {
    scwin.f_defaultValue();
    ica_adptDt.setValue(scwin.strCurDate);
};

scwin.onUdcCompleted = function () {
    scwin.f_OnLoad();
};

scwin.fn_setCommboGridEqKndCdAll = function () {
    ds_searchEqNrmCd.set("grpCd", "ZZ208");
    ds_searchEqNrmCd.set("queryId", "retrieveCodeListForCombo");
    ds_searchEqNrmCd.set("sysCd", "CommonEBC");

    $c.sbm.execute(sbm_eqNrmCd);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_defaultValue
// scwin.desc : 화면 open시 초기 데이타 setting
//-------------------------------------------------------------------------
scwin.f_defaultValue = function () {
    //오늘날짜 세팅
    ica_cnd_adptDt.setValue("");

    //버튼초기화 
    $c.gus.cfDisableObjects([btn_save, btn_add, btn_del, btn_cls, udc_portDistrictCd, ica_adptDt]);
    $c.gus.cfEnableObjects([btn_edit, btn_new]);

    //항목 Focus
    ed_cnd_portDistrictCd.focus();
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Addrow
// scwin.desc : 행추가
//-------------------------------------------------------------------------
scwin.f_addrow = function () {
    if (ds_basetrfList.getRowCount() == 0) {
        let row = ds_basetrfList.insertRow();
        ds_basetrfList.setCellData(row, "adptDt", ica_adptDt.getValue().trim());
        ds_basetrfList.setCellData(row, "portDistrictCd", ed_portDistrictCd.getValue().trim());
        ds_basetrfList.setCellData(row, "selpchItemCd", "0003");
        ds_basetrfList.setCellData(row, "crcCd", "KRW");
        ds_basetrfList.setCellData(row, "unitCd", "H/R"); //시간(H/R)
        ds_basetrfList.setCellData(row, "famtMainRtClsCd", "FM");  //정액        	
        gr_basetrfList.setFocusedCell(row, "eqKndCd", false);
    } else {
        $c.gus.cfCopyRecord(gr_basetrfList);
        let lastRow = ds_basetrfList.getRowCount() - 1;
        ds_basetrfList.setCellData(lastRow, "comnTrfSeq", 0);
        ds_basetrfList.setRowPosition(lastRow);
        gr_basetrfList.setFocusedCell(lastRow, "eqKndCd", false);
    }
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_undo
// scwin.desc : 취소
//-------------------------------------------------------------------------
scwin.f_undo = function () {
    if (ds_basetrfList.getRowStatus(ds_basetrfList.getRowPosition()) != 'R') {
        if (ds_basetrfList.getRowStatus(ds_basetrfList.getRowPosition()) != 'C') {
            ds_basetrfList.undoRow(ds_basetrfList.getRowPosition());
        } else {
            ds_basetrfList.removeRow(ds_basetrfList.getRowPosition());
        }
        //gr_basetrfList.setReadOnly("grid", true);
        //ds_basetrfList.Editable = false;
    }
};

//-------------------------------------------------------------------------
// 조회조건 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search, null);
    scwin.f_defaultValue();
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_validChk
// scwin.desc : 필수 조회 조건 check
//-------------------------------------------------------------------------
scwin.f_validChk = async function () {
    if (ds_basetrfList.getModifiedJSON().length > 0) {
        scwin.searchFlag = true;
        if (! await $c.win.confirm(scwin.MSG_LO_CRM_001)) {
            scwin.searchFlag = false;
            return false;
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Retrieve
// scwin.desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    //scwin.searchFlag = true;
    if (!await scwin.f_validChk()) {
        return;
    }
    ds_basetrfList.removeAll();
    ds_basetrfList.reform();
    ds_retrieve.setEmptyValue();
    ds_retrieve.set("portDistrictCd", ed_cnd_portDistrictCd.getValue().trim());
    ds_retrieve.set("adptDt", ica_cnd_adptDt.getValue().trim());

    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_RetrieveDetail
// scwin.desc : 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveDetail = function () {
    ds_retrieveDetail.setEmptyValue();
    ds_retrieveDetail.set("portDistrictCd", ds_basetrf.getCellData(ds_basetrf.getRowPosition(), "portDistrictCd"));
    ds_retrieveDetail.set("adptDt", ds_basetrf.getCellData(ds_basetrf.getRowPosition(), "adptDt"));

    $c.sbm.execute(sbm_retrieveDetail);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_New
// scwin.desc : 신규
//-------------------------------------------------------------------------
scwin.f_New = function () {
    //적용일자 초기화 세팅	
    ed_portDistrictCd.setValue("");
    ed_portDistrictNm.setValue("");
    ica_adptDt.setValue(scwin.strCurDate);

    ds_basetrfList.removeAll();
    ds_basetrfList.reform();
    gr_basetrfList.setReadOnly("grid", false);

    //$c.gus.cfEnableObjects([btn_save,btn_add,btn_del,btn_cls, ed_portDistrictCd,ed_portDistrictNm,imgPort, ica_adptDt,imgAdptDt]);
    $c.gus.cfEnableObjects([btn_save, btn_add, btn_del, btn_cls, udc_portDistrictCd, ica_adptDt]);
    $c.gus.cfDisableObjects([btn_edit, btn_new]);

    //항구권역에 Focus
    ed_portDistrictCd.focus();
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Edit
// scwin.desc : 수정
//-------------------------------------------------------------------------
scwin.f_Edit = function () {
    if (ds_basetrfList.getRowCount() > 0) {
        gr_basetrfList.setReadOnly("grid", false);

        $c.gus.cfEnableObjects([btn_save, btn_add, btn_del, btn_cls]);
        $c.gus.cfDisableObjects([btn_edit, btn_new]);
    } else {
        $c.gus.cfAlertMsg("조회 후 처리하시기 바랍니다.");
    }
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_Save
// scwin.desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (!await scwin.f_ReqFieldChk()) {
        return;
    }
    if (!await $c.win.confirm(MSG_CM_CRM_001)) {
        return;
    }
    scwin.f_CreateDs();

    //저장하기전 조회조건값 확인
    scwin.hid_portDistrictCd = ed_portDistrictCd.getValue().trim();
    scwin.hid_portDistrictNm = ed_portDistrictNm.getValue().trim();
    scwin.hid_adptDt = ica_adptDt.getValue().trim();

    scwin.pos_groupCode = ds_basetrf.getRowPosition();

    $c.sbm.execute(sbm_save);
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_ReqFieldChk
// scwin.desc : 필수 입력항목 체크
//-------------------------------------------------------------------------
scwin.f_ReqFieldChk = async function () {
    if (ds_basetrfList.getModifiedJSON().length < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["장비료"]);//"@은(는) 변경된 사항이 없습니다.";
        return false;
    }

    //항목
    if (!await $c.gus.cfValidate([ed_portDistrictCd], null, true)) {
        return false;
    }

    //적용일자
    if (!await $c.gus.cfValidate([ica_adptDt], null, true)) {
        return false;
    }

    // if (!await $c.gus.cfValidate([gr_basetrfList], null, true)) {
    //     return false;
    // }

    let validArry = [
        { id: "eqKndCd", name: "장비분류", key: false, mandatory: true },
        { id: "eqNrmCd", name: "장비규격", key: false, mandatory: true },
        { id: "crcCd", name: "통화", key: false, mandatory: true },
        { id: "comn", name: "금액/시간당", key: false, mandatory: true, minNumber: 0.01 },
        { id: "comn1", name: "반일대 금액", key: false },
        { id: "comn2", name: "전일대 금액", key: false }
    ];

    let gridName = "장비료상세목록";
    if (!await $c.gus.cfValidateGrid(gr_basetrfList, null, null, validArry, gridName)) {
        return false;
    }

    let errCnt = 0;
    for (let i = 0; i < ds_basetrfList.getRowCount(); i++) {
        for (let j = 0; j < ds_basetrfList.getRowCount(); j++) {
            if (i != j && ds_basetrfList.getCellData(i, 'eqKndCd') == ds_basetrfList.getCellData(j, 'eqKndCd')
                && ds_basetrfList.getCellData(i, 'eqNrmCd') == ds_basetrfList.getCellData(j, 'eqNrmCd')) {
                errCnt = j + 1;
                break;
            }
        }
        if (errCnt > 0) {
            $c.win.alert(gridName + "의 " + errCnt + "번째 데이터에서 장비분류, 장비규격은(는) 중복될 수 없습니다.");
            gr_basetrfList.setFocusedCell(errCnt - 1, 'eqNrmCd', false);
            return false;
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_CreateDs
// scwin.desc : 그리드DataId의 dataset을 서버로 넘길 dataset으로 변경
//-------------------------------------------------------------------------
scwin.f_CreateDs = function () {
    //적용일자 GRID에 세팅
    let edAdptDt = ica_adptDt.getValue().trim();
    for (i = 0; i < ds_basetrfList.getRowCount(); i++) {
        if (ds_basetrfList.getRowStatus(i) == 'C' || ds_basetrfList.getRowStatus(i) == 'U') {
            ds_basetrfList.setCellData(i, "adptDt", edAdptDt);

            if (ds_basetrfList.getCellData(i, "crcCd") == "KRW") {
                ds_basetrfList.setCellData(i, "comnTrf", ds_basetrfList.getCellData(i, "comn"));
                ds_basetrfList.setCellData(i, "comnTrf1", ds_basetrfList.getCellData(i, "comn1"));
                ds_basetrfList.setCellData(i, "comnTrf2", ds_basetrfList.getCellData(i, "comn2"));
                ds_basetrfList.setCellData(i, "comnTrfFcrc", 0);
                ds_basetrfList.setCellData(i, "comnTrfFcrc1", 0);
                ds_basetrfList.setCellData(i, "comnTrfFcrc2", 0);

            } else if (ds_basetrfList.getCellData(i, "crcCd") == "USD") {
                ds_basetrfList.setCellData(i, "comnTrf", 0);
                ds_basetrfList.setCellData(i, "comnTrf1", 0);
                ds_basetrfList.setCellData(i, "comnTrf2", 0);
                ds_basetrfList.setCellData(i, "comnTrfFcrc", ds_basetrfList.getCellData(i, "comn"));
                ds_basetrfList.setCellData(i, "comnTrfFcrc1", ds_basetrfList.getCellData(i, "comn1"));
                ds_basetrfList.setCellData(i, "comnTrfFcrc2", ds_basetrfList.getCellData(i, "comn2"));
            }

        }//end if			
    }//end for
};

//-------------------------------------------------------------------------
// scwin.name : scwin.f_openCommonPopUp
// scwin.desc : popup
// 임시로 광역권(WDE)로 세팅 -> 추후에 항구권으로 수정할것 (2005.12.7)
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        //항구권역 조회	    
        case 1:
            udc_cnd_portDistrictCd.setSelectId('retrieveDistrictList');
            rtnList = udc_cnd_portDistrictCd.cfCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_cnd_portDistrictCd, ed_cnd_portDistrictNm)
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '5'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null  		            // 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , ',,PCD'				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch				// 전체검색허용여부	("F")
                , '항구권역조회,권역코드,권역명'				    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case 2:
            udc_portDistrictCd.setSelectId('retrieveDistrictList');
            rtnList = udc_portDistrictCd.cfCommonPopUp((rtnList) => {
                $c.gus.cfSetReturnValue(rtnList, ed_portDistrictCd, ed_portDistrictNm);

                for (i = 0; i < ds_basetrfList.getRowCount(); i++) {
                    ds_basetrfList.setCellData(i, "portDistrictCd", rtnList[0]);
                }
            }
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '5'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null  		            // 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , ',,PCD'				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch				// 전체검색허용여부	("F")
                , '항구권역조회,권역코드,권역명'				    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.sbm_retrieve_submitdone = async function (e) {
    try {
        if (e.responseJSON.resultDataSet[0].Code < 0) {
            return; //onFail
        }
        let rowcnt = ds_basetrf.getRowCount();
        tbx_totalRows.setValue(rowcnt);
        $c.gus.cfEnableObjects([btn_new, btn_edit]);
        $c.gus.cfDisableObjects([btn_save, btn_add, btn_del, btn_cls, udc_portDistrictCd, ica_adptDt]);

        if (rowcnt == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            ed_portDistrictCd.setValue(ed_cnd_portDistrictCd.getValue().trim());
            ed_portDistrictNm.setValue(ed_cnd_portDistrictNm.getValue().trim());
            ica_adptDt.setValue(ica_cnd_adptDt.getValue().trim());
            return;
        }

        gr_basetrf.setFocusedCell(0, "portDistrictNm", false);
        $c.gus.cfGoPrevPosition(gr_basetrf, scwin.pos_groupCode);
        gr_basetrfList.setReadOnly("grid", true);
        scwin.searchFlag = false;
    } catch (e) {
        console.log("sbm_retrieve_submitdone : " + e);
    }
};

scwin.sbm_retrieveDetail_submitdone = async function (e) {
    try {
        if (e.responseJSON.resultDataSet[0].Code < 0) {
            return; //onFail
        }
        let rowcnt = ds_basetrfList.getRowCount();
        tbx_totalRows2.setValue(rowcnt);

        if (rowcnt > 0) {
            gr_basetrfList.setFocusedCell(0, "eqKndCd", false);
        }
    } catch (e) {
        console.log("sbm_retrieveDetail_submitdone : " + e);
    }
};

scwin.sbm_retrieveDetail_submiterror = function (e) {
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        return; //onFail
    }
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다 	

    //저장조건값을 조회조건값으로 세팅한다.    
    ed_cnd_portDistrictCd.setValue(scwin.hid_portDistrictCd);
    ed_cnd_portDistrictNm.setValue(scwin.hid_portDistrictNm);
    ica_cnd_adptDt.setValue(scwin.hid_adptDt);

    scwin.searchFlag = true;

    ds_basetrfList.removeAll();
    ds_basetrfList.reform();
    //조회
    scwin.f_Retrieve();
};

scwin.sbm_save_submiterror = function (e) {
};

scwin.btn_refresh_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_new_onclick = function (e) {
    scwin.f_New();
};

scwin.btn_edit_onclick = function (e) {
    scwin.f_Edit();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

